1	<script lang="ts">
2		// DotMeter v2, the judge's hand-built take, for direct iteration with Jake.
3		// The design thesis: multiply-and-add should be VISIBLE, not narrated.
4		// Every bar is literally its two products stacked; the strip below shows
5		// the arithmetic for whichever candidate you select, live. The meter's
6		// score prints to one decimal (so is the strip's final score, same
7		// quantity, same precision); the coordinate and product terms print to
8		// two, since those are a different quantity.
9	
10		// The two entries mean something: x is how loud, y is how fast.
11		const CANDIDATES = [
12			{ id: 'c1', name: 'Night Drive', angle: 20 },
13			{ id: 'c2', name: 'Glass Rain', angle: 70 },
14			{ id: 'c3', name: 'Slow Burn', angle: 110 },
15			{ id: 'c4', name: 'Static', angle: 160 }
16		];
17	
18		let challenge = $state<null | 'cheat' | 'short'>(null);
19		let solvedCheat = $state(false);
20		let solvedShort = $state(false);
21		const WHY = {
22			cheat:
23				'A song that is simply louder and faster everywhere piles up score without matching your mix. A raw meter overrates intense tracks, so a recommender built on it keeps pushing whatever is biggest.',
24			short:
25				'A quiet song that matches your mix exactly gets buried under bigger ones. Size is drowning direction, and fixing that is exactly where this lesson is headed.'
26		};
27		function startChallenge(kind: 'cheat' | 'short') {
28			// one click always re-arms: a solved card resets on first click,
29			// whether or not another challenge was active in between
30			if (kind === 'cheat' && (challenge === 'cheat' || solvedCheat)) solvedCheat = false;
31			if (kind === 'short' && (challenge === 'short' || solvedShort)) solvedShort = false;
32			challenge = kind;
33			probeAngle = 40;
34			lengthC1 = 1.0;
35			selected = 'c1';
36		}
37		$effect(() => {
38			if (challenge === 'cheat' && cheatActive) solvedCheat = true;
39			if (challenge === 'short' && shortChanged) solvedShort = true;
40		});
41	
42		let probeAngle = $state(40);
43		let lengthC1 = $state(1.0);
44		let selected = $state('c1');
45		let hovered = $state<string | null>(null);
46		let dragging = $state<'probe' | 'length' | null>(null);
47	
48		const rad = (d: number) => (d * Math.PI) / 180;
49	
50		const probe = $derived({ x: Math.cos(rad(probeAngle)), y: Math.sin(rad(probeAngle)) });
51	
52		const rows = $derived(
53			CANDIDATES.map((c) => {
54				const len = c.id === 'c1' ? lengthC1 : 1;
55				const x = len * Math.cos(rad(c.angle));
56				const y = len * Math.sin(rad(c.angle));
57				const px = probe.x * x; // the x-term product
58				const py = probe.y * y; // the y-term product
59				return { ...c, len, x, y, px, py, score: px + py };
60			})
61		);
62	
63		// Leadership is judged at the SAME precision the meter prints (one
64		// decimal): two scores that display the same digit must never crown
65		// one of them the leader, per the displayed-precision rule.
66		const displayScore = (n: number) => Math.round((Object.is(n, -0) ? 0 : n) * 10) / 10;
67		const maxDisplay = $derived(Math.max(...rows.map((r) => displayScore(r.score))));
68		const leaders = $derived(rows.filter((r) => displayScore(r.score) === maxDisplay).map((r) => r.id));
69		const tied = $derived(leaders.length > 1);
70		const sel = $derived(rows.find((r) => r.id === selected) ?? rows[0]);
71	
72		// The mirror lesson: c1 aims truest but is too short to win.
73		const shortChanged = $derived.by(() => {
74			const c1 = rows[0];
75			if (lengthC1 >= 0.95 || leaders.includes('c1')) return false;
76			return rows.every(
77				(r) =>
78					r.id === 'c1' ||
79					Math.abs(((r.angle - probeAngle + 540) % 360) - 180) >
80						Math.abs(((c1.angle - probeAngle + 540) % 360) - 180)
81			);
82		});
83	
84		// The overtake: c1 stretched AND outscoring a candidate that out-aligns it.
85		// Returns the most deserving victim (best-aligned beaten song) so the flag
86		// can name the exact pair instead of making a vague claim about the board.
87		const cheatVictim = $derived.by(() => {
88			const c1 = rows[0];
89			if (lengthC1 <= 1.05) return null;
90			const dist = (angle: number) => Math.abs(((angle - probeAngle + 540) % 360) - 180);
91			const beaten = rows.filter(
92				(r) =>
93					r.id !== 'c1' &&
94					dist(r.angle) < dist(c1.angle) &&
95					displayScore(c1.score) > displayScore(r.score)
96			);
97			if (beaten.length === 0) return null;
98			return beaten.reduce((a, b) => (dist(a.angle) < dist(b.angle) ? a : b));
99		});
100		const cheatActive = $derived(cheatVictim !== null);
101		const leaderName = $derived(rows.find((r) => r.id === leaders[0])?.name ?? '');
102	
103		// --- Arena geometry (SVG units) ---
104		const S = 400; // viewBox square
105		const CX = S / 2;
106		const CY = S / 2;
107		const R = 92; // unit arrow length in px; 2.0 x R stays inside the frame
108		const pt = (x: number, y: number) => ({ px: CX + x * R, py: CY - y * R });
109	
110		function arrow(x: number, y: number) {
111			const tip = pt(x, y);
112			const ang = Math.atan2(CY - tip.py, tip.px - CX);
113			const L = Math.hypot(tip.px - CX, tip.py - CY);
114			const head = Math.max(7, Math.min(11, L * 0.09));
115			const back = { px: tip.px - head * Math.cos(ang), py: tip.py + head * Math.sin(ang) };
116			const left = {
117				px: back.px - head * 0.55 * Math.sin(ang),
118				py: back.py - head * 0.55 * Math.cos(ang)
119			};
120			const right = {
121				px: back.px + head * 0.55 * Math.sin(ang),
122				py: back.py + head * 0.55 * Math.cos(ang)
123			};
124			return {
125				shaft: { x1: CX, y1: CY, x2: back.px, y2: back.py },
126				head: `${tip.px},${tip.py} ${left.px},${left.py} ${right.px},${right.py}`
127			};
128		}
129	
130		function labelPos(angle: number, len: number, pad = 20) {
131			const d = len * R + pad;
132			return { px: CX + d * Math.cos(rad(angle)), py: CY - d * Math.sin(rad(angle)) };
133		}
134	
135		let arenaEl = $state<SVGSVGElement | null>(null);
136	
137		function anglesFromEvent(e: PointerEvent) {
138			if (!arenaEl) return null;
139			const r = arenaEl.getBoundingClientRect();
140			const x = ((e.clientX - r.left) / r.width) * S - CX;
141			const y = CY - ((e.clientY - r.top) / r.height) * S;
142			return { angle: ((Math.atan2(y, x) * 180) / Math.PI + 360) % 360, dist: Math.hypot(x, y) / R };
143		}
144	
145		function onArenaPointer(e: PointerEvent) {
146			const a = anglesFromEvent(e);
147			if (!a || !dragging) return;
148			// Pointer drags resolve to 1 degree (smooth by hand, and a short
149			// near-radial drag still registers); arrow keys keep the spec's 5.
150			if (dragging === 'probe') probeAngle = Math.round(a.angle) % 360;
151			else lengthC1 = Math.max(0.5, Math.min(2, Math.round(a.dist * 10) / 10));
152		}
153	
154		function startDrag(kind: 'probe' | 'length', e: PointerEvent) {
155			dragging = kind;
156			(e.currentTarget as Element).setPointerCapture(e.pointerId);
157		}
158	
159		function probeKeys(e: KeyboardEvent) {
160			let h = true;
161			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') probeAngle = (probeAngle + 5) % 360;
162			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') probeAngle = (probeAngle + 355) % 360;
163			else h = false;
164			if (h) e.preventDefault();
165		}
166	
167		function lengthKeys(e: KeyboardEvent) {
168			let h = true;
169			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') lengthC1 = Math.min(2, Math.round((lengthC1 + 0.1) * 10) / 10);
170			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') lengthC1 = Math.max(0.5, Math.round((lengthC1 - 0.1) * 10) / 10);
171			else h = false;
172			if (h) e.preventDefault();
173		}
174	
175		const f = (n: number) => (Object.is(n, -0) ? 0 : n).toFixed(2);
176		const cl = (v: number) => Math.min(Math.max(v, 24), S - 24);
177		const f1 = (n: number) => (Object.is(n, -0) ? 0 : n).toFixed(1);
178	
179		// Bar scale: scores live in [-2, 2] once c1 can stretch.
180		const BARMAX = 2.05;
181		const barH = 96;
182		const segH = (v: number) => (Math.abs(v) / BARMAX) * (barH / 2);
183	
184		const probeTip = $derived(pt(probe.x, probe.y));
185		const c1row = $derived(rows[0]);
186		const c1HandlePos = $derived(pt(c1row.x, c1row.y));
187	</script>
188	
189	<svelte:window onpointerup={() => (dragging = null)} />
190	
191	<div class="lab" data-interactive="dot-alignment">
192		<p class="invite">
193			Every song here is two numbers: how <em class="qw-loud">loud</em>, how <em class="qw-fast">fast</em>. So is your taste. Turn
194			the amber taste arrow and watch each song's match get <em>built</em>: the <span class="qw-loud">loud product</span> plus
195			the <span class="qw-fast">fast product</span>, stacked into one bar. Then grab Night Drive's round handle and change its size.
196		</p>
197		<div class="challenges">
198			<button class="chal" class:active={challenge === 'cheat' && !solvedCheat} class:done={solvedCheat} onclick={() => startChallenge('cheat')}>
199				<span class="chal-t mono">challenge 01</span>
200				<span class="chal-g">Make a worse match win</span>
201				{#if solvedCheat}
202					<span class="chal-s mono">✓ solved · click to retry</span>
203					<span class="chal-why">{WHY.cheat}</span>
204				{:else if challenge === 'cheat'}
205					<span class="chal-s mono live">in play…</span>
206				{/if}
207			</button>
208			<button class="chal" class:active={challenge === 'short' && !solvedShort} class:done={solvedShort} onclick={() => startChallenge('short')}>
209				<span class="chal-t mono">challenge 02</span>
210				<span class="chal-g">Make the truest song lose</span>
211				{#if solvedShort}
212					<span class="chal-s mono">✓ solved · click to retry</span>
213					<span class="chal-why">{WHY.short}</span>
214				{:else if challenge === 'short'}
215					<span class="chal-s mono live">in play…</span>
216				{/if}
217			</button>
218		</div>
219	
220		<div class="stage">
221			<div class="arena-wrap">
222				<svg
223					bind:this={arenaEl}
224					viewBox="0 0 {S} {S}"
225					class="arena"
226					onpointermove={onArenaPointer}
227					role="img"
228					aria-label="An amber probe arrow among four periwinkle candidate arrows; drag the probe tip to turn it, drag c1's tip to stretch it"
229				>
230					<!-- angle ring + ticks -->
231					<circle cx={CX} cy={CY} r={R} class="ring" />
232					{#each Array.from({ length: 12 }, (_, i) => i * 30) as t (t)}
233						<line
234							x1={CX + (R - 4) * Math.cos(rad(t))}
235							y1={CY - (R - 4) * Math.sin(rad(t))}
236							x2={CX + (R + 4) * Math.cos(rad(t))}
237							y2={CY - (R + 4) * Math.sin(rad(t))}
238							class="tick"
239						/>
240					{/each}
241					<!-- axes, whisper-quiet, but named: the two entries ARE qualities -->
242					<line x1={CX - R - 14} y1={CY} x2={CX + R + 14} y2={CY} class="axis" />
243					<line x1={CX} y1={CY - R - 14} x2={CX} y2={CY + R + 14} class="axis" />
244					<text x={CX + R + 18} y={CY - 6} class="axisq q-loud mono" aria-hidden="true">loud</text>
245					<text x={CX - 10} y={CY - R - 8} text-anchor="end" class="axisq q-fast mono" aria-hidden="true">fast</text>
246	
247					<!-- coordinates made visible: dashed drops for probe and selected -->
248					{#each [{ x: probe.x, y: probe.y, cls: 'p' }, { x: sel.x, y: sel.y, cls: 'c' }] as d (d.cls)}
249						{@const tip = pt(d.x, d.y)}
250						<line x1={tip.px} y1={tip.py} x2={tip.px} y2={CY} class="drop {d.cls}" />
251						<line x1={tip.px} y1={tip.py} x2={CX} y2={tip.py} class="drop {d.cls}" />
252						<text x={cl(tip.px)} y={CY + (d.cls === 'p' ? 13 : 25)} class="coord mono {d.cls}" aria-hidden="true">{f(d.x)}</text>
253						<text x={CX - (d.cls === 'p' ? 4 : 32)} y={cl(tip.py) - 3} class="coord mono {d.cls}" text-anchor="end" aria-hidden="true">{f(d.y)}</text>
254					{/each}
255	
256					<!-- candidates -->
257					{#each rows as r (r.id)}
258						{@const a = arrow(r.x, r.y)}
259						<g
260							class="cand"
261							class:sel={selected === r.id}
262							class:hov={hovered === r.id}
263							onpointerdown={() => (selected = r.id)}
264							role="button"
265							tabindex="-1"
266							aria-label={`select ${r.name}`}
267						>
268							<line {...{ x1: a.shaft.x1, y1: a.shaft.y1, x2: a.shaft.x2, y2: a.shaft.y2 }} class="shaft cand-stroke" />
269							<polygon points={a.head} class="cand-fill" />
270						</g>
271					{/each}
272					<!-- candidate tip tags: c1..c4, always on and radially clear of the
273					     sweeping probe, so the id never gets buried mid-turn. Their
274					     story names live in the stable meter cards below. -->
275					{#each rows as r (r.id)}
276						{@const lp = labelPos(r.angle, r.len, 26)}
277						<text
278							x={Math.min(Math.max(lp.px, 44), S - 48)}
279							y={Math.min(Math.max(lp.py, 16), S - 10)}
280							class="lab song-lab halo"
281							class:sel={selected === r.id}
282							aria-hidden="true">{r.id}</text>
283					{/each}
284	
285					<!-- probe on top; its own tip tag is nudged off-angle so it never
286					     lands on top of a candidate's tag even when the probe points
287					     straight at that candidate. -->
288					{#if true}
289						{@const a = arrow(probe.x, probe.y)}
290						{@const plp = labelPos(probeAngle + 13, 1, 34)}
291						<line {...{ x1: a.shaft.x1, y1: a.shaft.y1, x2: a.shaft.x2, y2: a.shaft.y2 }} class="shaft probe-stroke" />
292						<polygon points={a.head} class="probe-fill" />
293						<text
294							x={Math.min(Math.max(plp.px, 44), S - 48)}
295							y={Math.min(Math.max(plp.py, 16), S - 10)}
296							class="lab probe-lab halo"
297							aria-hidden="true">probe</text>
298					{/if}
299					<circle
300						cx={probeTip.px}
301						cy={probeTip.py}
302						r="32"
303						onpointermove={onArenaPointer}
304						class="handle probe-handle"
305						class:active={dragging === 'probe'}
306						onpointerdown={(e) => startDrag('probe', e)}
307						onkeydown={probeKeys}
308						role="slider"
309						tabindex="0"
310						aria-label="probe angle in degrees"
311						aria-valuemin="0"
312						aria-valuemax="360"
313						aria-valuenow={Math.round(probeAngle)}
314					/>
315					<!-- Night Drive's length handle. AFTER the probe handle on purpose:
316					     the primary angle slider must be the FIRST [role="slider"] in
317					     the DOM (the drive contract grabs the first one). -->
318					<circle
319						cx={c1HandlePos.px}
320						cy={c1HandlePos.py}
321						r="32"
322						onpointermove={onArenaPointer}
323						class="handle length-handle"
324						class:active={dragging === 'length'}
325						class:pulse={challenge !== null && !((challenge === 'cheat' && cheatActive) || (challenge === 'short' && shortChanged))}
326						onpointerdown={(e) => startDrag('length', e)}
327						onkeydown={lengthKeys}
328						role="slider"
329						tabindex="0"
330						data-control="length-c1"
331						aria-label="c1 length"
332						aria-valuemin="0.5"
333						aria-valuemax="2"
334						aria-valuenow={f1(lengthC1)}
335					/>
336					<text x="14" y={S - 14} class="angle mono" aria-hidden="true">taste at {Math.round(probeAngle)}°</text>
337				</svg>
338			</div>
339	
340			<div class="meter">
341				{#each rows as r (r.id)}
342					<button
343						class="row"
344						class:leading={leaders.includes(r.id) && !tied}
345						class:sel={selected === r.id}
346						onmouseenter={() => (hovered = r.id)}
347						onmouseleave={() => (hovered = null)}
348						onclick={() => (selected = r.id)}
349						aria-label={`${r.id} score ${f1(r.score)}${leaders.includes(r.id) && !tied ? ', leading' : ''}`}
350					>
351						<span class="row-id">{r.name}</span>
352						<span class="bar" style="--h: {barH}px">
353							<span class="zero"></span>
354							<!-- x-term segment then y-term segment, stacked from the baseline -->
355							<span
356								class="seg segx"
357								class:neg={r.px < 0}
358								style="height: {segH(r.px)}px; bottom: {r.px >= 0 ? barH / 2 : barH / 2 - segH(r.px)}px"
359							></span>
360							<span
361								class="seg segy"
362								class:neg={r.py < 0}
363								style="height: {segH(r.py)}px; bottom: {r.py >= 0
364									? barH / 2 + (r.px > 0 ? segH(r.px) : 0)
365									: barH / 2 - segH(r.py) - (r.px < 0 ? segH(r.px) : 0)}px"
366							></span>
367						</span>
368						<span class="row-score mono" class:neg={r.score < 0}>{f1(r.score)}</span>
369						{#if leaders.includes(r.id) && !tied}<span class="leads mono">leads</span>{/if}
370					</button>
371				{/each}
372				{#if tied}<span class="tie mono">tied</span>{/if}
373				{#if cheatVictim}
374					<span class="flag mono">⚑ {cheatVictim.name} matches your taste better, but Night Drive outscores it on size</span>
375				{:else if shortChanged}
376					<span class="flag short mono">⚑ Night Drive matches best, but {leaderName} wins on size</span>
377				{/if}
378			</div>
379		</div>
380		{#if challenge === null && cheatActive}
381			<p class="why">Why this matters: {WHY.cheat}</p>
382		{:else if challenge === null && shortChanged}
383			<p class="why">Why this matters: {WHY.short}</p>
384		{/if}
385		<p class="hint">
386			Click any bar or arrow to inspect it. The dashed lines are that arrow's two
387			entries (its loudness and its speed), the numbers the recipe multiplies.
388		</p>
389	
390		<div class="strip" aria-live="polite">
391			<span class="strip-lead">the whole recipe, live for <b>{sel.name}</b>:</span>
392			<span class="mono eq">
393				<span class="op qw-loud">loud</span>
394				<span class="probe-c">{f(probe.x)}</span>·<span class="cand-c">{f(sel.x)}</span>
395				<span class="op">+</span>
396				<span class="op qw-fast">fast</span>
397				<span class="probe-c">{f(probe.y)}</span>·<span class="cand-c">{f(sel.y)}</span>
398				<span class="op">=</span>
399				<span class="segx-c">{f(sel.px)}</span>
400				<span class="op">+</span>
401				<span class="segy-c">{f(sel.py)}</span>
402				<span class="op">=</span>
403				<span class="score-c">{f1(sel.score)}</span>
404			</span>
405			<span class="strip-note">
406				multiply the matched entries, add the products. The <span class="qw-loud">lilac slice</span>
407				of each bar is its loud product, the <span class="qw-fast">mint slice</span> its fast
408				product; stacked, they are the score.
409			</span>
410		</div>
411	</div>
412	
413	<style>
414		.lab {
415			max-width: 860px;
416			margin: 2rem auto;
417			padding: 1.4rem 1.6rem 1.2rem;
418			background: var(--color-surface);
419			border: 1px solid color-mix(in oklab, var(--color-text) 8%, transparent);
420			border-radius: 14px;
421		}
422		.invite {
423			margin: 0 0 1rem;
424			font-size: 0.98rem;
425			line-height: 1.5;
426			color: color-mix(in oklab, var(--color-text) 88%, transparent);
427		}
428		.invite em { color: var(--color-brand-mint); font-style: normal; }
429		.invite .qw-loud, .lab .invite .qw-loud { color: var(--data-params); font-style: normal; }
430		.invite .qw-fast, .lab .invite .qw-fast { color: color-mix(in oklab, var(--color-brand-mint) 85%, var(--color-text)); font-style: normal; }
431		.mono { font-family: var(--font-mono); }
432	
433		.stage { display: flex; flex-direction: column; gap: 0.8rem; align-items: center; }
434		.arena-wrap { width: 100%; max-width: 620px; }
435		.arena { width: 100%; height: auto; touch-action: none; display: block; }
436	
437		.ring { fill: none; stroke: color-mix(in oklab, var(--color-text) 10%, transparent); stroke-width: 1; }
438		.tick { stroke: color-mix(in oklab, var(--color-text) 14%, transparent); stroke-width: 1; }
439		.axis { stroke: color-mix(in oklab, var(--color-text) 7%, transparent); stroke-width: 1; }
440	
441		.shaft { stroke-width: 2.4; stroke-linecap: round; }
442		.cand-stroke { stroke: var(--data-observed); }
443		.cand-fill { fill: var(--data-observed); }
444		.probe-stroke { stroke: var(--data-heat); }
445		.probe-fill { fill: var(--data-heat); }
446		.cand { opacity: 0.82; cursor: pointer; transition: opacity var(--motion-min-ms) var(--ease-out-quint); }
447		.cand.sel { opacity: 1; }
